/* must have a package.json */

var pkgjson = msg.contents.filter((d) => {
    return d.name == "package.json"
});

if ( pkgjson.length != 1 ) {
    if ( pkgjson.length > 1 ) {
      node.error("multiple package.json files found", msg)
    } else {
      node.error("no package.json file found", msg)
    }
    node.done();
    return;
}

/* name must be scoped */

var manifest = JSON.parse(pkgjson[0].contents);

var pdetails = manifest.name.split("/")

if (pdetails.length < 2 || pdetails[0][0] != '@') {
    node.error("package name not scoped: " + manifest.name, msg)
    node.done();
    return
}

/* need to provide an node-red supported engine version */

if ( !manifest["node-red"] || !manifest["node-red"].version ) {
    msg.error = {
      message: "Node-RED supported version missing in package.json, see https://nodered.org/docs/creating-nodes/packaging for more details"
    }
    node.error("Node-RED supported engine version not supplied in package.json", msg)
    node.done();
    return
}

/* also ensure there is an nodejs engine supported version salvo */

if ( !manifest.engines || !manifest.engines.node ) {
    msg.error = {
      message: "Nodejs supported version missing in package.json, see https://docs.npmjs.com/cli/v7/configuring-npm/package-json#engines for more details"
    }
    node.error("Nodejs supported engine version not supplied in package.json", msg)
    node.done();
    return
}

/* ensure contents is not empty */

msg.contents.forEach( (d) => {
  if ( !d.contents || d.contents.trim() == "" ) {
    node.error("file empty: " + d.name, msg)
    node.done();
    return
  }
});

