/**
 * Msg attributes:
 *   - owner: github repo owner
 *   - repo: github repo name
 *   - payload: sha of tree (i.e. directory)
 * 
 * Return:
 *   - payload: tree of the sha, this will be an array with one entry per member of tree
 */

try {

    octokit.request("GET /repos/{owner}/{repo}/git/trees/{tree_sha}?recursive=true", {
        owner: msg.owner,
        repo: msg.repo,
        tree_sha: msg.payload
    }).then( (resp) => {
        node.send({ ...msg, payload: resp.data.tree})
    }).catch(function (e) {
         node.error("obtaining tree", { ...msg, error: e })
    });

} catch (e) {
    node.error("something went wrong", { ...msg, error: e})
}

var shaLookup = {};

for ( var idx = 0 ; idx < msg.current_shas.length ; idx++ ) {
    shaLookup[msg.current_shas[idx].path] = msg.current_shas[idx].sha
}

msg.changes = msg.payload.filter( (d) => {
    return d.sha != shaLookup[d.path]
})

if ( msg.changes.length > 0 ) {
    return [msg, undefined];
} else {
    msg.payload = "github: no changes"
    return [undefined, msg];
}

