        ...msg,
        error: e
    })
    return undefined;
}

/**
 * Msg attributes:
 *   - owner: github repo owner
 *   - repo: github repo name
 *   - branch: branch name
 * 
 * Return:
 *   - payload: current revision of repo
 * 
 * Source:
 *   - https://docs.github.com/en/rest/branches/branches?apiVersion=2022-11-28#get-a-branch
 */

try {

    octokit.request("GET /repos/:owner/:repo/branches/:branch", {
        owner: msg.owner,
        repo: msg.repo,
        branch: msg.branch,
    }).then( (resp) => {
        node.send({ ...msg, payload: resp.data.commit.sha})
    }).catch(function (e) {
        node.error("obtaining latest sha", { ...msg, error: e })
    });

} catch (e) {
    node.error("request failure", { ...msg, error: e})
}

msg.payload = msg.contents.map( (elem) => {
    var newelem = { ...elem};

    if ( elem.type != "base64") {
        // @ts-ignore
        newelem.contents = RED.util.ensureBuffer(elem.contents).toString('base64')
    }

    delete newelem.type;
    return newelem;
})

return msg;

try {
    var octokit = new octokitRest.Octokit({ 
        auth: (msg.github && msg.github.access_token) || process.env.GITHUB_TOKEN 
    });
} catch(e) {
    node.error("init octokit", {
        ...msg,
        error: e
    })
    return undefined;
}

/**
 * Msg attributes:
 *   - owner: github repo owner
 *   - repo: github repo name
 *   - branch: github branch
 * 
 * Return:
 *   - payload: arrayBuffer of tarball content
 * 
 * Discussion:
 * 
 *   This request returns a redirect URL that octokit 
 *   automagically follows.
 * 
 */

try {

    octokit.request("GET /repos/:owner/:repo/tarball/:branch", {
        owner: msg.owner,
        repo: msg.repo,
        branch: msg.branch
    }).then( (resp) => {
        node.send({ 
            ...msg, 
            payload: resp.data, 
            dirname: resp.headers["content-disposition"].replace(/^.+filename=/,"").replace(/.tar.gz$/,'/') 
        })
    }).catch(function (e) {
         node.error("obtaining tree", { ...msg, error: e })
    });

} catch (e) {
    node.error("something went wrong", { ...msg, error: e})
}

msg.payload = msg.payload.filter( e =>  {
    return e.path != ""
})

return msg;

