    if (xhr.responseJSON) {
        message = xhr.responseJSON.message;
    }

    var notification = RED.notify(RED._('palette.editor.errors.removeFailed', { module: pkgname, message: message }), {
        type: 'error',
        modal: true,
        fixed: true,
        buttons: [
            {
                text: RED._("common.label.close"),
                click: function () {
                    notification.close();
                }
            }, {
                text: RED._("eventLog.view"),
                click: function () {
                    notification.close();
                    RED.actions.invoke("core:show-event-log");
                }
            }
        ]
    });
})

